export interface ActionPlan {
  id: string;
  title: string;
  issue: string;
  phases: {
    name: string;
    description: string;
    steps: { text: string; completed: boolean; status?: StepStatus }[];
  }[];
  scripts: { scenario: string; say: string; avoid: string }[];
  successIndicators: string[];
  // ── M9 lineage (all optional/additive): track regeneration of a plan in place,
  // so the closed loop can re-author phases/steps from progress while keeping the
  // same `id`. Absent on first-generation plans (treated as generation 1).
  /** 1 for the first generation; incremented on each regenerate-from-progress. */
  generation?: number;
  /** ISO timestamp of the last regenerate-from-progress (absent if never). */
  lastRegeneratedAt?: string;
  /** The focus challenge this plan was (re)generated for; seeds the next regen prompt. */
  challengeTopic?: string;
}

const cap = (s: string) => (s ? s[0].toUpperCase() + s.slice(1) : s);

// ── M9: the regenerate decision ──────────────────────────────────────────────
// Pure summary of "what changed since the last generation" that the regenerate
// route turns into a prompt: which steps the family completed vs. left undone,
// and which behaviors are still recurring. No I/O, no Date.now() — caller passes
// `today` — so it is unit-testable and reusable by an auto-trigger later.

export interface RegenerateDecision {
  /** False when there's nothing new to act on (no missed steps, no fresh signal). */
  shouldRegenerate: boolean;
  /** Human-readable reasons, safe to surface in UI or fold into the prompt. */
  reasons: string[];
  completedSteps: string[];
  /** Incomplete steps in started-but-unfinished phases — the "missed" work. */
  missedSteps: string[];
  /** Plan topics still showing up in recent logs (from suggestedChallenges). */
  stillRecurring: PlanSuggestion[];
  /** generation the regenerate would PRODUCE (prior generation + 1). */
  nextGeneration: number;
}

const stepText = (s: PlanStep): string => s.text;

/**
 * Decide whether (and why) to regenerate an existing plan from its progress plus
 * the child's recent behavior logs. "Missed" = incomplete steps that sit inside a
 * phase the family has already begun (at least one step done) — i.e. work that was
 * reachable but left behind, the signal that the plan needs re-shaping.
 */
export function regeneratePlanDecision(
  plan: ActionPlan,
  logs: BehaviorLog[],
  today: string
): RegenerateDecision {
  const phases = plan.phases ?? [];
  const completedSteps = phases.flatMap((p) => (p.steps ?? []).filter(stepDone).map(stepText));

  const missedSteps = phases.flatMap((p) => {
    const steps = p.steps ?? [];
    const phaseStarted = steps.some(stepDone);
    return phaseStarted ? steps.filter((s) => !stepDone(s)).map(stepText) : [];
  });

  const stillRecurring = suggestedChallenges(logs, today);
  const prog = planProgress(plan);

  const reasons: string[] = [];
  if (missedSteps.length > 0) {
    reasons.push(`${missedSteps.length} step(s) started but not finished — re-pace or replace them.`);
  }
  if (prog.planComplete) {
    reasons.push("The plan is fully complete — extend it to the next phase of the challenge.");
  }
  if (stillRecurring.length > 0) {
    reasons.push(`Recurring behavior still logged: ${stillRecurring.map((s) => s.topic.split("—")[0].trim()).join(", ")}.`);
  }
  if (completedSteps.length > 0 && reasons.length === 0) {
    reasons.push("Progress made — refresh the next steps to keep momentum.");
  }

  const nextGeneration = (plan.generation ?? 1) + 1;

  return {
    shouldRegenerate: missedSteps.length > 0 || prog.planComplete || stillRecurring.length > 0 || completedSteps.length > 0,
    reasons,
    completedSteps,
    missedSteps,
    stillRecurring,
    nextGeneration,
  };
}

