import type { BehaviorLog, PracticeEvent } from "../types";
import { EMOTIONS } from "./playContent";

/**
 * Mood Mirror (M6) — derive the child's MOST RECENT *explicitly logged* mood so
 * their avatar can wear it on the Today/Overview status band.
 *
 * CRITICAL SAFETY RULE: depicted-from-explicit-logs ONLY. We never INFER the
 * child's inner emotion from anything passive. The only accepted sources are:
 *   1. Feelings Lab SELF-reports — a `emotion-why` PracticeEvent whose `meta`
 *      starts with `self:` (the child saying "I feel X"). Scenario-matching
 *      `emotion-id` events are about a character in a story, NOT the child's own
 *      feeling, so they are deliberately ignored here.
 *   2. A behaviour log whose `behaviorType` *explicitly names* a known emotion
 *      (a deliberate mood tag the parent/child entered).
 */

export interface Mood {
  /** Emotion emoji for the avatar's expression badge. */
  emoji: string;
  /** Human label, e.g. "Happy". */
  label: string;
  /** CSS colour token for the avatar aura, e.g. "var(--arbor-yellow-ink)". */
  tone: string;
}

/** Each feeling's calm aura tone (mirrors Feelings Lab's EMOTION_TONE). */
const EMOTION_TONE: Record<string, string> = {
  happy: "var(--arbor-yellow-ink)",
  excited: "var(--arbor-peach-ink)",
  sad: "var(--arbor-sky-ink)",
  afraid: "var(--arbor-lav-ink)",
  angry: "var(--arbor-pink-ink)",
  frustrated: "var(--arbor-pink-ink)",
};

const DEFAULT_TONE = "var(--arbor-clay)";

/** Build a Mood from a known emotion id, or null if the id is unknown. */
function moodFromId(id: string | undefined | null): Mood | null {
  if (!id) return null;
  const emotion = EMOTIONS.find((e) => e.id === id);
  if (!emotion) return null;
  return { emoji: emotion.emoji, label: emotion.label, tone: EMOTION_TONE[emotion.id] ?? DEFAULT_TONE };
}

/**
 * Extract the child's self-reported emotion id from a Feelings Lab event, or
 * null when the event is not an explicit self-report. Only `emotion-why` events
 * tagged `self:<id>` count — everything else (scenario matching, calm rounds,
 * untagged whys) is passive/derived and must NOT drive the mood mirror.
 */
function selfReportedId(event: PracticeEvent): string | null {
  if (event.kind !== "emotion-why") return null;
  const meta = event.meta ?? "";
  if (!meta.startsWith("self:")) return null;
  const id = meta.slice("self:".length).trim();
  return id.length > 0 ? id : null;
}

/**
 * Extract an explicit mood id from a behaviour log: only when `behaviorType`
 * exactly names a known emotion id or label (case-insensitive). A normal
 * behaviour entry ("Transition Refusal") returns null.
 */
function loggedMoodId(log: BehaviorLog): string | null {
  const raw = (log.behaviorType ?? "").trim().toLowerCase();
  if (!raw) return null;
  const match = EMOTIONS.find((e) => e.id.toLowerCase() === raw || e.label.toLowerCase() === raw);
  return match ? match.id : null;
}

function ts(value: string | undefined): number {
  const n = value ? Date.parse(value) : NaN;
  return Number.isNaN(n) ? -Infinity : n;
}

/**
 * The child's latest explicitly-logged mood, or null when nothing qualifies.
 * Pure: no I/O, no React, no Date.now() — fully deterministic for a given input.
 */
export function latestMood(
  events: PracticeEvent[] = [],
  logs: BehaviorLog[] = []
): Mood | null {
  let bestTs = -Infinity;
  let bestId: string | null = null;

  for (const e of events) {
    const id = selfReportedId(e);
    if (!id) continue;
    const t = ts(e.timestamp);
    if (t > bestTs) {
      bestTs = t;
      bestId = id;
    }
  }

  for (const l of logs) {
    const id = loggedMoodId(l);
    if (!id) continue;
    const t = ts(l.timestamp);
    if (t > bestTs) {
      bestTs = t;
      bestId = id;
    }
  }

  return moodFromId(bestId);
}

