import { describe, expect, it } from "vitest";
import type { BehaviorLog, PracticeEvent } from "../types";
import { latestMood } from "./moodMirror";

const evt = (
  kind: PracticeEvent["kind"],
  meta: string | undefined,
  daysBack: number
): PracticeEvent => ({
  id: `${kind}-${daysBack}-${Math.random()}`,
  kind,
  domain: "emotional",
  meta,
  timestamp: new Date(Date.now() - daysBack * 86_400_000).toISOString(),
});

const log = (behaviorType: string, daysBack: number): BehaviorLog => ({
  id: `log-${daysBack}-${Math.random()}`,
  timestamp: new Date(Date.now() - daysBack * 86_400_000).toISOString(),
  behaviorType,
  intensity: 3,
  durationMinutes: 5,
  trigger: "",
  response: "",
});

describe("latestMood", () => {
  it("returns null with no inputs", () => {
    expect(latestMood()).toBeNull();
    expect(latestMood([], [])).toBeNull();
  });

  it("reads a Feelings Lab self-report (emotion-why meta self:<id>)", () => {
    const m = latestMood([evt("emotion-why", "self:happy", 1)]);
    expect(m).toEqual({ emoji: "😄", label: "Happy", tone: "var(--arbor-yellow-ink)" });
  });

  it("IGNORES scenario emotion-id events (about a character, not the child)", () => {
    // emotion-id is passive recognition of someone else's feeling — must not drive the mirror.
    expect(latestMood([evt("emotion-id", "scenario-3", 1)])).toBeNull();
  });

  it("IGNORES emotion-why whys that are not self-tagged", () => {
    expect(latestMood([evt("emotion-why", "sad", 1)])).toBeNull();
    expect(latestMood([evt("emotion-why", undefined, 1)])).toBeNull();
  });

  it("picks the most recent qualifying event", () => {
    const m = latestMood([
      evt("emotion-why", "self:sad", 5),
      evt("emotion-why", "self:excited", 1),
      evt("emotion-why", "self:angry", 9),
    ]);
    expect(m?.label).toBe("Excited");
  });

  it("reads an explicit emotion-tagged behaviour log (id or label, case-insensitive)", () => {
    expect(latestMood([], [log("afraid", 1)])?.label).toBe("Afraid");
    expect(latestMood([], [log("Angry", 1)])?.label).toBe("Angry");
  });

  it("IGNORES ordinary behaviour logs that do not name an emotion", () => {
    expect(latestMood([], [log("Transition Refusal", 1)])).toBeNull();
  });

  it("compares events and logs on one timeline, newest wins", () => {
    const newerLog = latestMood([evt("emotion-why", "self:sad", 3)], [log("happy", 1)]);
    expect(newerLog?.label).toBe("Happy");
    const newerEvent = latestMood([evt("emotion-why", "self:sad", 1)], [log("happy", 3)]);
    expect(newerEvent?.label).toBe("Sad");
  });

  it("returns null for an unknown emotion id", () => {
    expect(latestMood([evt("emotion-why", "self:zorp", 1)])).toBeNull();
  });
});
